{"fixed_code": "\"\"\"\nLEGIONHETO - Comprehensive LLM Fine-Tuning Framework\n======================================================\n\nA powerful framework for fine-tuning Large Language Models\nwith support for all major architectures and custom optimizations.\n\nQuick Start:\n>>> from legionheto import LegionHetoModel, SFTTrainer\n>>> model = LegionHetoModel(\"meta-llama/Llama-2-7b-hf\")\n>>> model.setup_lora(r=16, alpha=32)\n>>> trainer = SFTTrainer(model, dataset)\n>>> trainer.train()\n\nModules:\n- core: Model registry, configuration, memory optimization\n- models: Model loading with architecture detection\n- optim: Custom 8-bit AdamW optimizer\n- attention: Flash Attention 2 and DeepSeek MLA\n- train: SFT, DPO, and ORPO trainers\n- data: Universal data loader with streaming support\n- export: GGUF export and model merging\n- utils: Logging, checkpointing, helpers\n\"\"\"\n\n__version__ = \"0.2.0\"\n__author__ = \"LEGIONHETO Team\"\n\nfrom .models import LegionHetoModel, ModelLoader, ModelRegistry\nfrom .train import SFTTrainer, DPOTrainer, ORPOTrainer, RLOOTrainer, SimPOTrainer, IPOTrainer, KTOTrainer\nfrom .export import export_to_gguf, ModelMerger\nfrom .export.tensorrt import export_to_tensorrt_llm, TensorRTLLMExporter\nfrom .optim import AdamW8bit\nfrom .attention import FlashAttention, DeepSeekMLA, MemoryEfficientAttention\nfrom .data.synthetic import SelfInstructGenerator, EvolInstructGenerator\nfrom .eval.harness import LegionHetoHarness, EvaluationConfig\nfrom .utils.memory_profiler import MemoryProfiler, TrainingMemoryProfiler\nfrom .utils.dashboard import WandbDashboard, ConsoleDashboard, create_dashboard\n\n__all__ = [\n    \"LegionHetoModel\",\n    \"ModelLoader\",\n    \"ModelRegistry\",\n    \"SFTTrainer\",\n    \"DPOTrainer\",\n    \"ORPOTrainer\",\n    \"RLOOTrainer\",\n    \"SimPOTrainer\",\n    \"IPOTrainer\",\n    \"KTOTrainer\",\n    \"export_to_gguf\",\n    \"export_to_tensorrt_llm\",\n    \"TensorRTLLMExporter\",\n    \"ModelMerger\",\n    \"AdamW8bit\",\n    \"FlashAttention\",\n    \"DeepSeekMLA\",\n    \"MemoryEfficientAttention\",\n    \"SelfInstructGenerator\",\n    \"EvolInstructGenerator\",\n    \"LegionHetoHarness\",\n    \"EvaluationConfig\",\n    \"MemoryProfiler\",\n    \"TrainingMemoryProfiler\",\n    \"WandbDashboard\",\n    \"ConsoleDashboard\",\n    \"create_dashboard\",\n]"}